/**
 * Tests for batch file operations and project scaffolding
 */

import { createCreateMultipleFilesHandler } from '../src/tools/handlers/createMultipleFiles.js';
import fs from 'fs/promises';
import path from 'path';

// Mock FileSystemManager
class MockFileSystemManager {
  constructor() {
    this.createdFiles = new Map();
    this.createdDirectories = new Set();
    this.shouldFailAt = null;
  }

  async writeFile(filePath, content) {
    if (this.shouldFailAt === filePath) {
      throw new Error(`Simulated failure for ${filePath}`);
    }
    this.createdFiles.set(filePath, content);
  }

  async createDirectory(dirPath) {
    this.createdDirectories.add(dirPath);
  }

  reset() {
    this.createdFiles.clear();
    this.createdDirectories.clear();
    this.shouldFailAt = null;
  }

  simulateFailureAt(filePath) {
    this.shouldFailAt = filePath;
  }
}

describe('Batch File Operations', () => {
  let mockFileSystemManager;
  let createMultipleFilesHandler;

  beforeEach(() => {
    mockFileSystemManager = new MockFileSystemManager();
    createMultipleFilesHandler = createCreateMultipleFilesHandler(mockFileSystemManager);
  });

  describe('createMultipleFiles', () => {
    test('should create multiple files successfully', async () => {
      const files = [
        { path: 'file1.txt', content: 'Content 1' },
        { path: 'file2.txt', content: 'Content 2' },
        { path: 'dir/file3.txt', content: 'Content 3' }
      ];

      const result = await createMultipleFilesHandler({ files });

      expect(result.success).toBe(true);
      expect(result.successCount).toBe(3);
      expect(result.errorCount).toBe(0);
      expect(result.createdFiles).toEqual(['file1.txt', 'file2.txt', 'dir/file3.txt']);
      expect(mockFileSystemManager.createdFiles.size).toBe(3);
      expect(mockFileSystemManager.createdDirectories.has('dir')).toBe(true);
    });

    test('should validate file parameters', async () => {
      const files = [
        { path: 'valid.txt', content: 'Valid content' },
        { path: '', content: 'Invalid path' },
        { path: 'missing-content.txt' },
        { path: '../traversal.txt', content: 'Path traversal attempt' }
      ];

      const result = await createMultipleFilesHandler({ 
        files, 
        rollbackOnError: false 
      });

      expect(result.success).toBe(false);
      expect(result.successCount).toBe(1);
      expect(result.errorCount).toBe(3);
      expect(result.errors).toHaveLength(3);
    });

    test('should handle rollback on error', async () => {
      const files = [
        { path: 'file1.txt', content: 'Content 1' },
        { path: 'file2.txt', content: 'Content 2' },
        { path: 'file3.txt', content: 'Content 3' }
      ];

      // Simulate failure on second file
      mockFileSystemManager.simulateFailureAt('file2.txt');

      await expect(
        createMultipleFilesHandler({ files, rollbackOnError: true })
      ).rejects.toThrow('File creation failed at file2.txt');

      // Should have created first file but then rolled back
      expect(mockFileSystemManager.createdFiles.size).toBe(1);
    });

    test('should continue on error when rollback disabled', async () => {
      const files = [
        { path: 'file1.txt', content: 'Content 1' },
        { path: 'file2.txt', content: 'Content 2' },
        { path: 'file3.txt', content: 'Content 3' }
      ];

      // Simulate failure on second file
      mockFileSystemManager.simulateFailureAt('file2.txt');

      const result = await createMultipleFilesHandler({ 
        files, 
        rollbackOnError: false 
      });

      expect(result.success).toBe(false);
      expect(result.successCount).toBe(2);
      expect(result.errorCount).toBe(1);
      expect(result.createdFiles).toEqual(['file1.txt', 'file3.txt']);
    });

    test('should enforce file limits', async () => {
      const files = new Array(1001).fill(0).map((_, i) => ({
        path: `file${i}.txt`,
        content: 'content'
      }));

      await expect(
        createMultipleFilesHandler({ files })
      ).rejects.toThrow('Too many files: 1001 (maximum 1000 files per batch)');
    });

    test('should validate file size limits', async () => {
      const largeContent = 'x'.repeat(11 * 1024 * 1024); // 11MB
      const files = [
        { path: 'large.txt', content: largeContent }
      ];

      const result = await createMultipleFilesHandler({ files });

      expect(result.success).toBe(false);
      expect(result.errors[0].error).toContain('File too large');
    });

    test('should handle empty files array', async () => {
      await expect(
        createMultipleFilesHandler({ files: [] })
      ).rejects.toThrow('Files array cannot be empty');
    });

    test('should handle invalid input', async () => {
      await expect(
        createMultipleFilesHandler({ files: 'not-an-array' })
      ).rejects.toThrow('Files parameter must be an array');
    });
  });

  describe('getProjectTemplate (mocked)', () => {
    // Mock template handler for testing
    const mockGetProjectTemplateHandler = () => async (params) => {
      const { template, projectName = 'My Project' } = params;

      if (!template) {
        return {
          success: true,
          availableTemplates: [
            { id: 'static-website', name: 'Static Website', description: 'Basic HTML/CSS/JS' },
            { id: 'react-app', name: 'React App', description: 'React application' }
          ],
          totalTemplates: 2,
          message: 'Available project templates'
        };
      }

      if (template === 'static-website') {
        return {
          success: true,
          template,
          projectName,
          fileCount: 4,
          files: [
            { path: 'index.html', content: `<html><title>${projectName}</title></html>` },
            { path: 'css/style.css', content: 'body { margin: 0; }' },
            { path: 'js/main.js', content: `console.log('${projectName}');` },
            { path: 'README.md', content: `# ${projectName}` }
          ]
        };
      }

      return {
        success: false,
        error: 'Template not found',
        availableTemplates: ['static-website', 'react-app']
      };
    };

    test('should return available templates when no template specified', async () => {
      const handler = mockGetProjectTemplateHandler();
      const result = await handler({});

      expect(result.success).toBe(true);
      expect(result.availableTemplates).toBeDefined();
      expect(Array.isArray(result.availableTemplates)).toBe(true);
      expect(result.totalTemplates).toBe(2);
    });

    test('should generate template files', async () => {
      const handler = mockGetProjectTemplateHandler();
      const result = await handler({
        template: 'static-website',
        projectName: 'Test Project'
      });

      expect(result.success).toBe(true);
      expect(result.template).toBe('static-website');
      expect(result.projectName).toBe('Test Project');
      expect(result.fileCount).toBe(4);
      expect(Array.isArray(result.files)).toBe(true);
      expect(result.files[0]).toHaveProperty('path');
      expect(result.files[0]).toHaveProperty('content');
    });

    test('should handle invalid template', async () => {
      const handler = mockGetProjectTemplateHandler();
      const result = await handler({
        template: 'non-existent-template'
      });

      expect(result.success).toBe(false);
      expect(result.error).toBeDefined();
      expect(result.availableTemplates).toBeDefined();
    });

    test('should use default project name', async () => {
      const handler = mockGetProjectTemplateHandler();
      const result = await handler({
        template: 'static-website'
      });

      expect(result.success).toBe(true);
      expect(result.projectName).toBe('My Project');
    });
  });

  describe('Integration Tests', () => {
    test('should create complete project from template', async () => {
      // Mock template files
      const templateFiles = [
        { path: 'index.html', content: '<html><title>Integration Test Project</title></html>' },
        { path: 'css/style.css', content: 'body { margin: 0; }' },
        { path: 'js/main.js', content: 'console.log("Integration Test Project");' },
        { path: 'README.md', content: '# Integration Test Project' }
      ];

      // Create files from template
      const createResult = await createMultipleFilesHandler({
        files: templateFiles,
        rollbackOnError: true,
        createDirectories: true
      });

      expect(createResult.success).toBe(true);
      expect(createResult.successCount).toBe(templateFiles.length);
      expect(createResult.createdFiles.length).toBe(templateFiles.length);

      // Verify content contains project name
      const indexContent = mockFileSystemManager.createdFiles.get('index.html');
      expect(indexContent).toContain('Integration Test Project');
    });

    test('should handle large project creation', async () => {
      // Create a large number of files
      const files = [];
      for (let i = 0; i < 100; i++) {
        files.push({
          path: `dir${Math.floor(i / 10)}/file${i}.txt`,
          content: `Content for file ${i}`
        });
      }

      const result = await createMultipleFilesHandler({
        files,
        rollbackOnError: false,
        createDirectories: true
      });

      expect(result.success).toBe(true);
      expect(result.successCount).toBe(100);
      expect(result.createdDirectories.length).toBeGreaterThan(0);
    });
  });
});

