describe('Error Handling', () => {
  test('should provide detailed error information', async () => {
    const mockFileSystemManager = new MockFileSystemManager();
    const createMultipleFilesHandler = createCreateMultipleFilesHandler(mockFileSystemManager);

    const files = [
      { path: 'valid.txt', content: 'Valid' },
      { path: '', content: 'Invalid path' },
      { path: 'valid2.txt', content: 'Valid 2' }
    ];

    const result = await createMultipleFilesHandler({ 
      files, 
      rollbackOnError: false 
    });

    expect(result.success).toBe(false);
    expect(result.errors).toHaveLength(1);
    expect(result.errors[0]).toHaveProperty('index');
    expect(result.errors[0]).toHaveProperty('file');
    expect(result.errors[0]).toHaveProperty('error');
  });
});